import{_ as a,o as t,c as o,a2 as n}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-007 — Separate nginx volume for data directory","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-007.md","filePath":"adr/ADR-007.md"}'),d={name:"adr/ADR-007.md"};function i(r,e,s,c,l,p){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="adr-007-—-separate-nginx-volume-for-data-directory" tabindex="-1">ADR-007 — Separate nginx volume for data directory <a class="header-anchor" href="#adr-007-—-separate-nginx-volume-for-data-directory" aria-label="Permalink to &quot;ADR-007 — Separate nginx volume for data directory&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-01 TA anchor · §stack Scope note (April 2026) · Applicable only to the self-hosted nginx + Docker Compose deployment path. The GitHub Pages preview environment (ADR-014) does not use this mechanism — it deploys a single static build artifact. Production hosting is TBD per ADR-014; this ADR remains valid for any self-hosted nginx deployment that wants independent data release cycles.</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Mission data in <code>data/</code> changes independently from the application bundle in <code>dist/</code>. Updating a mission date or adding a new mission should not require rebuilding and redeploying the JavaScript bundle.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Mount <code>data/</code> as a separate Docker volume from <code>dist/</code>. The docker-compose.yml has two volume mounts: <code>./dist:/usr/share/nginx/html:ro</code> and <code>./data:/usr/share/nginx/html/data:ro</code>. Updating <code>data/</code> and running <code>docker compose restart</code> takes effect immediately without a build step.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Follows directly from ADR-006. If data is in JSON files, the deployment should make data updates cheap. A contributor who edits a JSON file should not need to run the build pipeline to deploy their change.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>Single volume for both dist and data — simpler compose file; couples data update cost to build cost.</li><li>Serve data from a separate port/service — adds operational complexity for no benefit.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: data contributors never need to run the build; data and code have independent release cycles. Negative: slightly more complex docker-compose.yml; <code>data/</code> paths must be consistent between local dev (<code>/data/</code>) and production.</p>',12)])])}const m=a(d,[["render",i]]);export{u as __pageData,m as default};
